import base64
import io
import json
import math
import zipfile
from PIL import Image, ImageColor, ImageDraw, ImageFont

SW, SH, SG = 1500, 900, 300
MODAL_W, DIALOG_W = 800, 520
OVERLAY_BASE_Y = SH + 200
OVERLAY_GAP_Y = 120
OVERLAY_COL_GAP = 120
MODAL_X_OFFSET = 110


def _to_number(value, default=0.0):
    try:
        return float(value)
    except Exception:
        return float(default)


def _label_from_node(node):
    for key in ("txt", "label", "placeholder"):
        value = node.get(key)
        if isinstance(value, str) and value.strip():
            return value.strip()
    return ""


def _max_extent(elements):
    max_h = 0

    def walk(node):
        nonlocal max_h
        try:
            y = int(node.get("y", 0))
            h = int(node.get("h", 0))
            max_h = max(max_h, y + h)
        except Exception:
            pass
        children = node.get("ch")
        if isinstance(children, list):
            for child in children:
                if isinstance(child, dict):
                    walk(child)

    if isinstance(elements, list):
        for element in elements:
            if isinstance(element, dict):
                walk(element)
    return max_h


def _estimate_overlay_h(extent, is_modal):
    if is_modal:
        return int(max(420, min(700, 220 + extent * 0.5)))
    return int(max(320, min(520, 170 + extent * 0.35)))


def _dialog_option_count(elements):
    count = 0

    def walk(node):
        nonlocal count
        if _label_from_node(node):
            count += 1
        children = node.get("ch")
        if isinstance(children, list):
            for child in children:
                if isinstance(child, dict):
                    walk(child)

    if isinstance(elements, list):
        for element in elements:
            if isinstance(element, dict):
                walk(element)
    return count


def _compute_frames(dsl):
    frames = []
    screens = dsl.get("screens") if isinstance(dsl, dict) else []
    modals = dsl.get("modals") if isinstance(dsl, dict) else []
    dialogs = dsl.get("dialogs") if isinstance(dsl, dict) else []

    screens = screens if isinstance(screens, list) else []
    modals = modals if isinstance(modals, list) else []
    dialogs = dialogs if isinstance(dialogs, list) else []

    screen_idx = {}
    for index, screen in enumerate(screens):
        if not isinstance(screen, dict):
            continue
        sid = str(screen.get("id") or f"S{index+1}")
        sname = str(screen.get("name") or sid)
        fx = index * (SW + SG)
        screen_idx[sid] = index
        frames.append(
            {
                "id": sid,
                "name": sname,
                "type": "screen",
                "x": fx,
                "y": 0,
                "w": SW,
                "h": SH,
            }
        )

    modal_cursor_y = {}
    for index, modal in enumerate(modals):
        if not isinstance(modal, dict):
            continue
        mid = str(modal.get("id") or f"M{index+1}")
        mname = str(modal.get("name") or mid)
        parent = str(modal.get("parentScreen") or "")
        sidx = screen_idx.get(parent, index)
        sx = sidx * (SW + SG)
        x = sx + MODAL_X_OFFSET
        y = float(modal_cursor_y.get(parent, OVERLAY_BASE_Y))
        oh = _estimate_overlay_h(_max_extent(modal.get("elements")), True)
        frames.append(
            {
                "id": mid,
                "name": mname,
                "type": "modal",
                "parentScreen": parent,
                "x": x,
                "y": y,
                "w": MODAL_W,
                "h": oh,
            }
        )
        modal_cursor_y[parent] = y + oh + OVERLAY_GAP_Y

    dialog_cursor_y = {}
    for index, dialog in enumerate(dialogs):
        if not isinstance(dialog, dict):
            continue
        did = str(dialog.get("id") or f"D{index+1}")
        dname = str(dialog.get("name") or did)
        parent = str(dialog.get("parentScreen") or "")
        sidx = screen_idx.get(parent, index)
        sx = sidx * (SW + SG)
        x = sx + MODAL_X_OFFSET + MODAL_W + OVERLAY_COL_GAP
        y = float(dialog_cursor_y.get(parent, OVERLAY_BASE_Y))
        options_count = _dialog_option_count(dialog.get("elements"))
        oh = max(88, min(620, max(1, options_count) * 44))
        frames.append(
            {
                "id": did,
                "name": dname,
                "type": "dialog",
                "parentScreen": parent,
                "x": x,
                "y": y,
                "w": DIALOG_W,
                "h": oh,
            }
        )
        dialog_cursor_y[parent] = y + oh + OVERLAY_GAP_Y

    return frames


def _element_bounds(element):
    x = _to_number(element.get("x"), 0)
    y = _to_number(element.get("y"), 0)
    w = _to_number(element.get("width"), _to_number(element.get("w"), 0))
    h = _to_number(element.get("height"), _to_number(element.get("h"), 0))
    if w < 0:
        w = 0
    if h < 0:
        h = 0
    return {"x": x, "y": y, "w": w, "h": h}


def _intersects(a, b):
    return not (
        a["x"] + a["w"] < b["x"]
        or a["x"] > b["x"] + b["w"]
        or a["y"] + a["h"] < b["y"]
        or a["y"] > b["y"] + b["h"]
    )


def _elements_overall_bbox(elements):
    xs = []
    ys = []
    x2 = []
    y2 = []
    if not isinstance(elements, list):
        return None
    for element in elements:
        if not isinstance(element, dict) or element.get("isDeleted"):
            continue
        b = _element_bounds(element)
        xs.append(b["x"])
        ys.append(b["y"])
        x2.append(b["x"] + b["w"])
        y2.append(b["y"] + b["h"])
    if not xs:
        return None
    return {"x": min(xs), "y": min(ys), "w": max(x2) - min(xs), "h": max(y2) - min(ys)}


def _overview_bbox(frames, elements):
    if frames:
        min_x = min(float(frame["x"]) for frame in frames)
        min_y = min(float(frame["y"]) for frame in frames) - 36
        max_x = max(float(frame["x"]) + float(frame["w"]) for frame in frames)
        max_y = max(float(frame["y"]) + float(frame["h"]) for frame in frames) + 24
        return {"x": min_x, "y": min_y, "w": max_x - min_x, "h": max_y - min_y}
    bbox = _elements_overall_bbox(elements)
    if bbox:
        return bbox
    return {"x": 0.0, "y": 0.0, "w": 1200.0, "h": 800.0}


def _color_to_rgba(value, alpha=255, fallback="#000000"):
    color = str(value or fallback).strip()
    if color.lower() in ("", "none", "transparent"):
        return (0, 0, 0, 0)
    try:
        rgb = ImageColor.getrgb(color)
        if len(rgb) == 4:
            return (rgb[0], rgb[1], rgb[2], int(max(0, min(255, alpha))))
        return (rgb[0], rgb[1], rgb[2], int(max(0, min(255, alpha))))
    except Exception:
        rgb = ImageColor.getrgb(fallback)
        return (rgb[0], rgb[1], rgb[2], int(max(0, min(255, alpha))))


def _pick_font(size):
    size = max(8, int(size))
    for path in (
        "/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf",
        "/usr/share/fonts/TTF/DejaVuSans.ttf",
    ):
        try:
            return ImageFont.truetype(path, size=size)
        except Exception:
            continue
    return ImageFont.load_default()


def _render_png(elements, bbox, padding):
    px = float(bbox["x"]) - float(padding)
    py = float(bbox["y"]) - float(padding)
    pw = max(1.0, float(bbox["w"]) + 2.0 * float(padding))
    ph = max(1.0, float(bbox["h"]) + 2.0 * float(padding))
    width = int(math.ceil(pw))
    height = int(math.ceil(ph))

    ox = -px
    oy = -py

    img = Image.new("RGBA", (width, height), _color_to_rgba("#F7F7F7"))
    draw = ImageDraw.Draw(img, "RGBA")

    if isinstance(elements, list):
        for element in elements:
            if not isinstance(element, dict) or element.get("isDeleted"):
                continue

            etype = str(element.get("type") or "")
            x = _to_number(element.get("x"), 0) + ox
            y = _to_number(element.get("y"), 0) + oy
            w = max(0.0, _to_number(element.get("width"), 0))
            h = max(0.0, _to_number(element.get("height"), 0))
            stroke_w = max(1, int(round(_to_number(element.get("strokeWidth"), 1))))
            opacity = max(0.0, min(1.0, _to_number(element.get("opacity"), 100) / 100.0))
            alpha = int(255 * opacity)

            stroke = _color_to_rgba(element.get("strokeColor"), alpha=alpha, fallback="#000000")
            fill = _color_to_rgba(element.get("backgroundColor"), alpha=alpha, fallback="#FFFFFF")
            if str(element.get("backgroundColor") or "").lower() in ("", "none", "transparent"):
                fill = (0, 0, 0, 0)

            if etype == "rectangle":
                x2 = x + w
                y2 = y + h
                radius = 8 if element.get("roundness") else 0
                if radius > 0:
                    draw.rounded_rectangle((x, y, x2, y2), radius=radius, fill=fill, outline=stroke, width=stroke_w)
                else:
                    draw.rectangle((x, y, x2, y2), fill=fill, outline=stroke, width=stroke_w)
            elif etype == "ellipse":
                x2 = x + w
                y2 = y + h
                draw.ellipse((x, y, x2, y2), fill=fill, outline=stroke, width=stroke_w)
            elif etype == "text":
                text_value = str(element.get("text") or "")
                if not text_value:
                    continue
                fs = max(8, int(_to_number(element.get("fontSize"), 14)))
                font = _pick_font(fs)
                line_height = int(fs * 1.25)
                for idx, line in enumerate(text_value.splitlines() or [""]):
                    draw.text((x, y + idx * line_height), line, fill=stroke, font=font)

    out = io.BytesIO()
    img.save(out, format="PNG")
    return out.getvalue()


def _frame_asset_path(frame):
    ftype = str(frame.get("type") or "screen")
    folder = "screens"
    if ftype == "modal":
        folder = "modals"
    elif ftype == "dialog":
        folder = "dialogs"
    return f"{folder}/{frame.get('id', 'item')}.png"


outputs = []
for item in _items:
    src = item.get("json", {}) if isinstance(item, dict) else {}
    bin_in = item.get("binary", {}) if isinstance(item, dict) and isinstance(item.get("binary"), dict) else {}
    out_json = dict(src)
    out_binary = dict(bin_in)

    try:
        raw_design = src.get("design")
        raw_dsl = src.get("designDsl")

        if isinstance(raw_design, str):
            design = json.loads(raw_design)
        elif isinstance(raw_design, dict):
            design = raw_design
        else:
            design = {"elements": []}

        if isinstance(raw_dsl, str):
            dsl = json.loads(raw_dsl)
        elif isinstance(raw_dsl, dict):
            dsl = raw_dsl
        else:
            dsl = {"screens": [], "modals": [], "dialogs": []}

        elements = design.get("elements")
        if not isinstance(elements, list):
            elements = []

        frames = _compute_frames(dsl)
        overview = _overview_bbox(frames, elements)

        manifest_assets = []
        zip_buffer = io.BytesIO()
        with zipfile.ZipFile(zip_buffer, "w", zipfile.ZIP_DEFLATED) as zf:
            overview_png = _render_png(elements, overview, 32)
            zf.writestr("overview.png", overview_png)
            manifest_assets.append(
                {
                    "id": "overview",
                    "type": "overview",
                    "path": "overview.png",
                    "bbox": overview,
                    "elementCount": len(elements),
                }
            )

            for frame in frames:
                frame_box = {
                    "x": float(frame["x"]),
                    "y": float(frame["y"]) - 36.0,
                    "w": float(frame["w"]),
                    "h": float(frame["h"]) + 56.0,
                }
                subset = []
                for element in elements:
                    if isinstance(element, dict) and _intersects(_element_bounds(element), frame_box):
                        subset.append(element)

                path = _frame_asset_path(frame)
                png = _render_png(subset, frame_box, 16)
                zf.writestr(path, png)
                manifest_assets.append(
                    {
                        "id": frame.get("id"),
                        "name": frame.get("name"),
                        "type": frame.get("type"),
                        "path": path,
                        "bbox": frame_box,
                        "elementCount": len(subset),
                        "parentScreen": frame.get("parentScreen"),
                    }
                )

        manifest = {
            "counts": {
                "screens": sum(1 for f in frames if f.get("type") == "screen"),
                "modals": sum(1 for f in frames if f.get("type") == "modal"),
                "dialogs": sum(1 for f in frames if f.get("type") == "dialog"),
                "images": len(manifest_assets),
            },
            "assets": manifest_assets,
        }

        zip_bytes = zip_buffer.getvalue()
        revision = int(src.get("revisionNumber", 0) or 0)
        zip_name = f"design-assets-r{revision}.zip"

        out_binary["reviewZip"] = {
            "data": base64.b64encode(zip_bytes).decode("ascii"),
            "mimeType": "application/zip",
            "fileName": zip_name,
            "fileExtension": "zip",
            "fileSize": str(len(zip_bytes)),
        }
        out_json["designAssetCount"] = len(manifest_assets)
        out_json["designAssetManifest"] = manifest
        out_json["response"] = str(src.get("response") or f"Design assets ZIP generated: {manifest['counts']['images']} PNG images + source file.")
        out_json.pop("designAssetError", None)
    except Exception as err:
        out_json["designAssetCount"] = 0
        out_json["designAssetError"] = str(err)
        out_json["response"] = str(src.get("response") or "Failed to build design assets ZIP.")

    outputs.append({"json": out_json, "binary": out_binary})

return outputs

