const item = $input.first() ?? { json: {}, binary: {} };
const currentJson = item.json ?? {};
const rawBinary = item.binary ?? {};

function getNodeItemSafe(nodeName) {
  if (typeof $items !== 'function') return null;
  try {
    return ($items(nodeName) || [])[0] || null;
  } catch {
    return null;
  }
}

function cleanJson(source) {
  const json = { ...(source ?? {}) };
  delete json.feedback;
  delete json.Feedback;
  delete json.Approved;
  delete json['Start Again'];
  delete json.reviewMode;
  delete json.isRefinementInteraction;
  delete json.designDsl;
  delete json.firstIterationDesignDsl;
  return json;
}

function cleanBinary(source) {
  return Object.fromEntries(
    Object.entries(source ?? {})
      .filter(([key]) => !/^attachments?(?:_|$)/i.test(String(key)))
      .filter(([key]) => !String(key).endsWith('_firstIteration')),
  );
}

function firstNonEmpty(values) {
  for (const value of values) {
    if (typeof value === 'string' && value.trim()) return value.trim();
  }
  return '';
}

function makeTextBinary(text, fileName, mimeType) {
  const value = String(text ?? '').trim();
  if (!value) return null;
  return {
    data: Buffer.from(value, 'utf8').toString('base64'),
    fileName,
    mimeType,
  };
}

const firstNode = getNodeItemSafe('DESIGN - Prepare Information for First Iteration');
const firstJson = cleanJson(firstNode?.json ?? {});
const baseJson = cleanJson(currentJson);

const currentValue = firstNonEmpty([
  currentJson.finalDesignExcalidraw,
  currentJson.design,
  currentJson.response,
]);

const cleanCurrentBinary = cleanBinary(rawBinary);
const currentArtifact = makeTextBinary(currentValue, 'design.excalidraw.json', 'application/json');
if (currentArtifact) cleanCurrentBinary.design = currentArtifact;

const firstValue = firstNonEmpty([
  firstJson.finalDesignExcalidraw,
  firstJson.design,
  baseJson.firstIterationDesign,
  currentValue,
]);

const firstArtifact = makeTextBinary(firstValue, 'design.excalidraw.json', 'application/json');
const inheritedFirst = rawBinary.design_firstIteration;
if (firstArtifact || inheritedFirst) cleanCurrentBinary.design_firstIteration = firstArtifact || inheritedFirst;

const outputJson = {
  ...baseJson,
  reviewMode: '',
  design: currentValue,
  finalDesignExcalidraw: currentValue,
  firstIterationDesign: firstValue,
  firstIterationReviewRevisionNumber: Number(firstJson.revisionNumber ?? baseJson.firstIterationReviewRevisionNumber ?? baseJson.revisionNumber ?? 0) || 0,
  firstIterationReviewZipDownloadUrl: String(firstJson.zipDownloadUrl ?? baseJson.firstIterationReviewZipDownloadUrl ?? baseJson.zipDownloadUrl ?? '').trim(),
  firstIterationReviewZipDownloadToken: String(firstJson.zipDownloadToken ?? baseJson.firstIterationReviewZipDownloadToken ?? baseJson.zipDownloadToken ?? '').trim(),
  firstIterationReviewDownloadLinkHtml: String(firstJson.downloadLinkHtml ?? baseJson.firstIterationReviewDownloadLinkHtml ?? baseJson.downloadLinkHtml ?? '').trim(),
};

delete outputJson.designDsl;
delete outputJson.firstIterationDesignDsl;

return [{
  json: outputJson,
  ...(Object.keys(cleanCurrentBinary).length ? { binary: cleanCurrentBinary } : {}),
}];

const item = $input.first() ?? { json: {}, binary: {} };
const json = { ...(item.json ?? {}) };
for (const key of ['Approved', 'Start Again', 'Feedback', 'feedback', 'Attachments (optional)', 'reviewMode', 'isRefinementInteraction', 'designDsl', 'firstIterationDesignDsl']) {
